operations.old:
.tab-btn.active {
  background: var(--accent);
  color: white;
  box-shadow: 0 10px 22px rgba(11, 92, 171, 0.22);
  transform: rotate(180deg) translateX(-8px);
}

operations.new:
.tab-btn.active {
  background: var(--accent);
  color: white;
  box-shadow: 0 10px 22px rgba(11, 92, 171, 0.22);
  transform: rotate(180deg) translateX(-8px);
}

.tab-btn:not(.active):hover {
  transform: rotate(180deg);
}

.tab-btn:hover,
.tab-btn:not(.active):hover {
  transform: none;
}

.tab-btn.active {
  transform: none;
  box-shadow: 0 6px 14px rgba(11, 92, 171, 0.2);
}
